-- Blink.cmp - Fast completion engine
-- Minimal setup for nvim-mini

return {
  {
    "saghen/blink.cmp",
    dependencies = {
      "rafamadriz/friendly-snippets",
      "Kaiser-Yang/blink-cmp-git",
    },
    version = "v0.*",
    event = { "InsertEnter", "CmdlineEnter" },
    opts = {
      enabled = function()
        return vim.bo.filetype ~= "AgenticInput"
          and vim.bo.filetype ~= "gwtt-prompt"
          and vim.bo.buftype ~= "prompt"
      end,

      -- Appearance

    col = "50%", -- Center horizontally
  },
  size = {
    width = "auto",
    height = "auto",
    min_width = 40, -- Minimum width
    max_width = 90, -- Maximum width to prevent overflow
  },
  win_options = {
    wrap = true, -- Enable text wrapping
    linebreak = true, -- Break at word boundaries
  },
},
messages = {
  view = "notify",  -- Use notify instead of split buffer
},
split = {
  backend = "split",
  relative = "editor",
  position = "bottom",

-- sidekick.nvim - Copilot NES and in-editor AI CLI launcher
-- OpenCode remains the canonical agent runtime; Sidekick is for learning-oriented suggestions.

local function cli_send(msg)
  return function()
    require("sidekick.cli").send({ msg = msg })
  end
end

return {
  {
    "folke/sidekick.nvim",
    keys = {
      {
        "<leader>asc",
        function() require("sidekick.cli").toggle({ name = "opencode", focus = true }) end,
        mode = { "n", "t" },
        desc = "Toggle Sidekick OpenCode",
      },
      {

---@class sidekick.config: sidekick.Config
local M = {}

M.ns = vim.api.nvim_create_namespace("sidekick.ui")

---@class sidekick.Config
local defaults = {
  nes = {
    ---@type boolean|fun(buf:integer):boolean?
    enabled = function(buf)
      return vim.g.sidekick_nes ~= false and vim.b.sidekick_nes ~= false
    end,
    debounce = 100,
    trigger = {
      -- events that trigger sidekick next edit suggestions
      events = { "ModeChanged i:n", "TextChanged", "User SidekickNesDone" },
    },
    clear = {
      -- events that clear the current next edit suggestion
      events = { "TextChangedI", "InsertEnter" },

---@param filter? vim.lsp.get_clients.Filter
---@return vim.lsp.Client[]
function M.get_clients(filter)
  return vim.tbl_filter(M.is_copilot, vim.lsp.get_clients(filter))
end

---@param buf? number
function M.get_client(buf)
  return M.get_clients({ bufnr = buf or 0 })[1]
