// OpenCode plugin: capture SSE events for Entire + Diffview integration
// Writes a JSONL log for all events and persists diff snapshots so
// Diffview (inside Neovim) can replay or inspect AI edits later.
// Also mirrors summarized payloads into Entire hooks for checkpoints.
import type { Plugin } from "@opencode-ai/plugin"
import path from "node:path"
import { mkdir, appendFile, writeFile } from "node:fs/promises"
import { spawn } from "node:child_process"
import crypto from "node:crypto"

type OpencodeEvent = {
  type?: string
  timestamp?: string
  properties?: Record<string, any>
}

type NormalizedEvent = {
  type: string
  timestamp: string
  session_id: string | null

import { existsSync } from "node:fs"
import { join } from "node:path"
import type { Plugin } from "@opencode-ai/plugin"

type HookResult = {
  stdout: string
  stderr: string
  exitCode: number
}

type ToolPayload = {
  tool_name: string
  tool_input: Record<string, unknown>
  tool_output?: string
  session_id?: string
}

const DOTFILES_ROOT = join(process.env.HOME || "", "dotfiles")
const CLAUDE_HOOKS_DIR = join(DOTFILES_ROOT, ".claude", "hooks")
const TMUX_HOOKS_DIR = join(DOTFILES_ROOT, "scripts", "tmux", "hooks")

